VALUES
  ('fire-eq-tech-moex-03290', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '木材的熱分解，溫度愈高，速度愈快，一般而言，木材的「危險溫度」為多少度？', '["60℃", "160℃", "260℃", "360℃"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03291', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '火災進入最盛期之燃燒可分為通風控制燃燒及燃料控制燃燒兩類，下列有關燃料控制燃燒之敘述何者錯誤？', '["燃燒速度由燃料表面積所控制", "燃燒速度與通風量無關", "因室外較暖空氣之大量滲入，使室溫升高，延燒持續時間延長", "容易經由開口向上層延燒"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03292', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '液體汽化為氣體的速度極為快速時，因能量在極短時間內放出，因而形成爆炸現象，稱為：', '["蒸氣爆炸", "分解爆炸", "瓦斯爆炸", "粉塵爆炸"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03293', 'fire-eq-tech', 'fire-eq-tech-moex-097-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '含氣泡的硝化甘油運輸中，易產生爆炸的原因為：', '["氣體斷熱壓縮", "點火能量小", "分解熱", "發火溫度低"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "75a2171b794e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "302", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
